"""
MKT Original Language Commentary — Esther chapters 1–5
Run: python3 scripts/zc-original-esther-1-5-full.py

Ch 1: Ahasuerus's 180-day feast → Vashti's refusal → her deposition.
Ch 2: Beauty-contest search → Esther introduced → her selection as queen →
  Mordecai saves the king → the act goes unrecorded.
Ch 3: Haman's elevation → Mordecai's refusal to bow → Haman's genocidal decree.
Ch 4: Mordecai's mourning → Esther's dilemma → 'for such a time as this' →
  Esther's three-day fast before entering the king's presence.
Ch 5: Esther before the king → the two-banquet strategy → Haman's pride and rage →
  the 50-cubit gallows.

Key linguistic observations:
- ʾAḥašwērôš: Hebrew rendering of Xerxes I (ruled 486-465 BCE); the three-term title
  formula in 1:1 (his kingdom, India to Ethiopia, 127 provinces) establishes imperial scope
- šûšan habbîrāh ('Susa the citadel', H7800 + H1002): the Persian capital-fortress;
  bîrāh is a loanword from Akkadian bīrtu (fortified palace complex)
- yāpeh-mārʾeh (fair of form) and ṭôḇaṯ-marʾeh (good of appearance): the doubled
  beauty formula for Esther (2:7) matches that for Rachel (Gen 29:17) and Joseph (Gen 39:6)
- pûr (3:7): the Akkadian loanword 'lot/dice' that names the Purim feast; only in Esther
- zākar/šāḵaḥ (remember/forget): the two verbs that frame the entire plot — Mordecai
  remembered (6:2) when his loyalty was almost forgotten
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EST_ORIGINAL_1_5 = {
  "1": {
    "1": "<p><strong>wayhî bîmê ʾAḥašwērôš</strong> — 'And it was in the days of Ahasuerus.' The Hebrew name <em>ʾAḥašwērôš</em> (H325) represents the Persian name <em>Xšayāršā</em>, rendered in Greek as Xerxes. The wayyiqtol-opening formula <em>wayhî bîmê</em> (and it was in the days of) is the standard biblical narrative opener for stories set within a defined historical period (cf. Ruth 1:1; 2 Sam 21:1; Isa 7:1). <strong>hûʾ ʾAḥašwērôš hammōšēl mēhōddû wəʿaḏ-kûš</strong> — 'he is the Ahasuerus who reigned from India to Ethiopia.' The relative clause with <em>hûʾ</em> as the pronoun of identification — 'he is the one who...' — is a narrative authentication formula, linking this king to a historically known figure. <em>Mēhōddû wəʿaḏ-kûš</em> (from India to Ethiopia) maps the empire's east-west extent. <strong>šeḇaʿ wəʿeśrîm ûməʾāh məḏînāh</strong> — 'one hundred and twenty-seven provinces.' The number 127 (<em>šbʿ wʿśrym wmʾh</em>) is unusually specific; Persian administrative texts list 20-30 satrapies, but the number may count sub-districts within satrapies.</p>",
    "2": "<p><strong>bayyāmîm hāhēm kəšeḇeṯ hammeleḵ ʾAḥašwērôš ʿal kissēʾ malkûṯô</strong> — 'In those days when King Ahasuerus sat on the throne of his kingdom.' <em>Šēḇeṯ ʿal kissēʾ</em> (sitting on the throne) is the idiom for reigning in full royal authority; the throne (<em>kissēʾ</em>, H3678) denotes both the physical seat and the regal authority it embodies. <strong>ʾăšer bəšûšan habbîrāh</strong> — 'which was in Susa the citadel.' <em>Bîrāh</em> (H1002) is a loanword from Akkadian <em>bīrtu</em> designating a fortified palace-complex or acropolis; it occurs elsewhere in Esther, Nehemiah, and Chronicles for fortified palace precincts. Susa (modern Shush, southwest Iran) served as one of the Persian royal capitals alongside Persepolis and Ecbatana.</p>",
    "3": "<p><strong>bišnaṯ šālôš ləmalkûṯô ʿāśāh mišṭeh</strong> — 'In the third year of his reign he made a feast.' <em>Mišṭeh</em> (H4960 = drinking feast, banquet; from <em>šāṯāh</em>, to drink) — this word appears 20 times in Esther, far more than in any other OT book; the repetition makes the feast/banquet the book's central social institution. <strong>ləḵol-śārāyw waʿăḇāḏāyw</strong> — 'for all his officials and servants.' The social scope is total: military commanders, Persian and Median nobles, and provincial governors. The feast is a display of imperial power through conspicuous hospitality.</p>",
    "4": "<p><strong>bəharʾōṯô ʾeṯ-ʿōšer kəḇôḏ malkûṯô</strong> — 'as he displayed the wealth (<em>ʿōšer</em>, H6239 = riches) of the glory (<em>kəḇôḏ</em>, H3519 = heaviness, weight, honor) of his kingdom.' The paired nouns — wealth and honor — are the terms for Persian imperial glory. The 180-day display period is the ostensive purpose of the feast: to impress the provincial nobility with the magnificence of the empire. <strong>wəyəqār tip̄ʾereṯ gəḏûlāṯô</strong> — 'and the honor (<em>yəqār</em>, H3366) and splendor (<em>tip̄ʾereṯ</em>, H8597) of his greatness' — the full vocabulary of Persian court glory. <strong>yāmîm rabbîm šəmônîm ûməʾaṯ yôm</strong> — 'many days, one hundred and eighty days.' The six-month duration is historically extraordinary; it signals that this is a programmatic imperial showcase, not a social occasion.</p>",
    "5": "<p><strong>ûḇimlōʾṯ hayyāmîm hāʾēlleh ʿāśāh hammeleḵ</strong> — 'And when these days were completed, the king made.' The 180-day display for the nobility is followed by a 7-day feast for the general population of Susa. <strong>ləḵol-hāʿām hannimṣāʾ bəšûšan habbîrāh</strong> — 'for all the people who were found in Susa the citadel' — <em>hāʿām hannimṣāʾ</em> (the people who were found/present) includes both the permanent residents and temporary visitors in the capital. <strong>miqāṭōn wəʿaḏ-gāḏôl šiḇʿaṯ yāmîm</strong> — 'from small to great, seven days.' The merism <em>miqāṭōn wəʿaḏ-gāḏôl</em> (from small to great) designates all social strata — the feast extends royal generosity to the entire population without regard to rank.</p>",
    "6": "<p><strong>ḥûr karpaṣ ûtəḵēleṯ ʾāḥûz bəḥaḇlê-ḇûṣ wəʾargāmān</strong> — 'white cotton and violet hangings fastened with cords of fine linen (<em>ḇûṣ</em>, H948) and purple.' The verse is an inventory of luxury textiles: white cotton (<em>ḥûr</em>, H2353), blue-violet <em>təḵēleṯ</em> (H8504, the dye from the <em>Murex</em> sea snail), fine linen bûṣ, and red-purple <em>ʾargāmān</em> (H713, also from Murex; the distinction is in the specific dye compound). <strong>ʿal-gəlîlê kesef wəʿammûḏê šēš</strong> — 'on silver rings and marble pillars.' The furniture terms continue: <em>gālîl</em> (H1530 = cylinder, roller; here probably curtain rings or rods), <em>ʾammûḏ</em> (H5982 = pillar/column), and <em>šēš</em> (H8336 = alabaster or white marble). The verse's purpose is to establish the visual vocabulary of Persian royal luxury that will recur when Esther enters this space.</p>",
    "7": "<p><strong>wəhašqôṯ biklê zāhāḇ wəḵēlîm mikkēlîm šônîm</strong> — 'drinks in vessels of gold, and vessels differing from vessel to vessel.' <em>Wəḵēlîm mikkēlîm šônîm</em> — the idiom 'vessels differing from vessels' emphasizes variety: no two drinking vessels were alike, each unique in design. The plural <em>kēlîm</em> (H3627 = vessels, implements) with the participle <em>šônîm</em> (H8138, qal = different, various) emphasizes the absence of repetition even in the material culture of the feast. <strong>wəyên malkûṯ rāḇ kəyaḏ hammāleḵ</strong> — 'and royal wine was plentiful according to the bounty (<em>yaḏ</em> = hand, lit. the hand) of the king.' <em>Kəyaḏ hammeleḵ</em> (according to the king's hand) is an idiom for generous, proportionate giving — the king's hand sets the measure of abundance.</p>",
    "8": "<p><strong>wəhašṭiyyāh ḵaddāṯ ʾên ʾōnēs</strong> — 'And the drinking was according to the law: no compulsion.' <em>Dāṯ</em> (H1881 = law, decree, custom) is a Persian loanword that appears 20 times in Esther — the book's central institutional term. Here the 'law' is against forcing guests to drink: a notable contrast with typical symposium practice where the host determined the wine ratio. <strong>kî-ḵēn yissaḏ hammeleḵ ʿal kol-raḇ bêṯô</strong> — 'for so the king had given orders to all the stewards of his house.' The king's personal decree creates an atmosphere of voluntary festivity rather than coerced performance — an irony given that the same king will shortly issue decrees that destroy lives.</p>",
    "9": "<p><strong>gam waštî hammalkāh ʿāśəṯāh mišṭeh nāšîm</strong> — 'Also Vashti the queen made a feast for the women.' The particle <em>gam</em> (also, even) introduces the parallel feast: while the king feasts the men, Vashti feasts the women in a separate part of the royal house. The separate-feast arrangement reflects ancient Near Eastern royal custom where men and women dined in separate spaces in the Persian court. <em>Bêṯ hammalkûṯ</em> (the royal house) refers to the queen's palace apartment within the palace complex.</p>",
    "10": "<p><strong>bayyôm haššəḇîʿî kəṭôḇ lēḇ-hammeleḵ bayyāyin</strong> — 'On the seventh day, when the heart of the king was merry with wine.' <em>Kəṭôḇ lēḇ</em> (when the heart was good/merry, H3820) is the idiom for a mood of expansive well-being induced by festivity — not necessarily drunkenness but a state of elevated social confidence. <strong>ʾāmar ləMehûmān Bizzəṯāʾ Ḥarḇônāʾ Bigṯāʾ</strong> — 'he commanded Mehuman, Bizzetha, Harbona, Bigtha.' The seven eunuchs are named — a literary device that gives the royal command its full official weight and will allow Harbona to reappear importantly in ch7. <strong>šiḇʿaṯ hassārîsîm hamməšārəṯîm ʾeṯ-pənê hammeleḵ ʾAḥašwērôš</strong> — 'the seven eunuchs who served in the presence of King Ahasuerus.' <em>Sārîs</em> (H5631 = eunuch, court official) is the standard Persian court term for the royal attendants; they form the interface between the king's will and its execution.</p>",
    "11": "<p><strong>lhāḇîʾ ʾeṯ-waštî hammalkāh lip̄nê hammeleḵ bəḵeter malkûṯ</strong> — 'to bring Vashti the queen before the king with her royal crown.' <em>Keter</em> (H3804 = crown, diadem; a Persian loanword from Old Persian <em>*xtra-</em>) — the royal headpiece that marks her status. The command is to bring her wearing the crown: the public display of the queen's beauty is as much a display of royal possessions as the 180-day exhibition of palace treasures. <strong>lharʾôṯ hāʿammîm wəhassārîm ʾeṯ-yapyāh</strong> — 'to show the peoples and the officials her beauty.' The command to display the queen publicly to a male audience violated the Persian norm of female seclusion in the royal court — a tension that explains the intensity of the reaction to her refusal.</p>",
    "12": "<p><strong>watməʾan hammalkāh waštî lāḇôʾ biḏbar hammeleḵ ʾăšer bəyaḏ hassārîsîm</strong> — 'But Queen Vashti refused to come at the king's word by the hand of the eunuchs.' The verb <em>māʾan</em> (H3985, piel = to refuse, be unwilling) is unambiguous: a direct refusal to obey a royal command. <strong>wayyiqṣōp̄ hammeleḵ məʾōḏ waḥămaṯô bāʿărāh bô</strong> — 'The king was very angry and his wrath burned in him.' The double description — extreme anger (<em>qāṣap̄</em>, H7107 = to be furious, enraged) and burning wrath (<em>ḥēmāh bāʿar</em> = wrath burned) — emphasizes that the public setting has made the refusal a matter of imperial face: a queen has defied the king before his assembled nobles.</p>",
    "13": "<p><strong>wayyōʾmer hammeleḵ laḥăḵāmîm yōḏəʿê hāʿittîm</strong> — 'Then the king spoke to the wise men who knew the times.' <em>Yōḏəʿê hāʿittîm</em> (H3045 + H6256 = knowers of the times) designates the king's official legal-religious advisors who understood the calendar, the legal precedents, and the proper protocol for the current situation. <strong>kî-ḵēn dəḇar hammeleḵ lip̄nê kol-yōḏəʿê dāṯ wāḏîn</strong> — 'for so was the king's custom toward all who knew law and judgment.' <em>Dāṯ wāḏîn</em> (H1881 + H1779 = law and judgment) are the paired legal terms for the Persian legal system.</p>",
    "14": "<p><strong>wəhaqqārōḇ ʾēlāyw Karšənāʾ Šēṯār ʾAḏmāṯāʾ Taršîš Meres Marsənāʾ Məmûḵān</strong> — 'The ones nearest to him were Carshena, Shethar, Admatha, Tarshish, Meres, Marsena, Memucan.' Seven wise men are named — the inner circle of royal counselors. The number seven mirrors the seven eunuchs of v10, creating a formal parallel between the two groups. These 'princes of Persia and Media who saw the king's face' (<em>rōʾê pənê hammeleḵ</em>) constitute the highest advisory body in the empire.</p>",
    "15": "<p><strong>māh laʿăśôṯ baqqōlet waštî hammalkāh</strong> — 'What shall be done to Queen Vashti according to the law?' The king frames the question as a legal inquiry: the refusal of a royal command requires a legal determination of the consequences. <em>Qōlet</em> (H6944-related; here: queen's conduct/offense) — the word is from <em>malkāh</em> context; the issue is that she has violated a royal command. <strong>ʿal ʾăšer lōʾ-ʿāśəṯāh ʾeṯ-maʾămar hammeleḵ ʾAḥašwērôš</strong> — 'because she did not perform the command of King Ahasuerus.' The legal indictment is stated precisely: non-performance of a royal <em>maʾămar</em> (H3982 = utterance, command, word of authority).</p>",
    "16": "<p><strong>wayyōʾmer Məmûḵān lip̄nê hammeleḵ wəhassārîm</strong> — 'Memucan answered before the king and the officials.' Memucan speaks as the lead counselor — his answer is the official legal opinion of the seven advisors. <strong>lōʾ ʿal-hammeleḵ lbaddô ʿāwəṯāh waštî hammalkāh</strong> — 'Vashti the queen has not wronged the king alone.' The term <em>ʿāwaṯ</em> (H5753, qal = to do wrong, act perversely; here the piel-like force of causing wrong) is the legal term for actionable wrongdoing. Memucan elevates the offense from a marital dispute to a state matter: the queen's refusal sets a precedent that threatens social order throughout the empire.</p>",
    "17": "<p><strong>kî-yēṣēʾ dəḇar-hammalkāh ʿal-kol-hannāšîm</strong> — 'for the queen's deed will become known to all women.' The concern is contagion: Vashti's refusal will be reported (phrased as the 'word going out,' <em>yāṣāʾ dāḇār</em>) and will embolden wives throughout the empire to follow suit. <strong>ləhab·zôṯ baʿlêhem bəʿênêhen</strong> — 'making their husbands contemptible in their eyes' (<em>bāzāh</em>, H959 = to despise, treat with contempt). The anxiety is cultural: wives holding husbands in contempt = social hierarchy destabilized. <strong>baʾămōr hammeleḵ ʾAḥašwērôš ʾāmar lhāḇîʾ ʾeṯ-waštî hammalkāh ləp̄ānāyw wəlōʾ-ḇāʾāh</strong> — 'when they say, King Ahasuerus commanded Vashti the queen to be brought before him and she did not come.'</p>",
    "18": "<p><strong>wəhayyôm hazzeh tōʾmarnah śārôṯ Pāras ûMāḏay</strong> — 'And today the women of Persia and Media who have heard of the queen's deed will say the same to all the king's officials.' The temporal urgency — <em>hayyôm hazzeh</em> (this very day) — drives the recommendation for immediate action before the precedent spreads further. <strong>wəkadday bizzāyôn wāqāṣep̄</strong> — 'and there will be contempt and wrath enough.' The counsel is that inaction will breed more contempt and the king's wrath will be further inflamed.</p>",
    "19": "<p><strong>ʾim-ʿal-hammeleḵ ṭôḇ yēṣēʾ dəḇar-malkûṯ millěp̄ānāyw</strong> — 'If it pleases the king, let a royal decree go forth from him.' <em>Dəḇar-malkûṯ</em> (H1697 + H4438 = word of the kingdom/royal edict) — an irrevocable royal pronouncement. <strong>wəyikkāṯēḇ bəḏāṯê P̄āras ûMāḏay wəlōʾ yaʿăḇōr</strong> — 'and let it be written among the laws of Persia and Media so that it may not be altered.' The principle of irrevocable Persian-Median law (cf. Dan 6:8,12,15 — a law of the Medes and Persians cannot be revoked) will return in ch8 as the central legal problem when the anti-Jewish decree cannot be rescinded. <strong>ʾăšer lōʾ-ḇāʾāh lip̄nê hammeleḵ wəmalkûṯāh yitēn hammeleḵ lirəʿûṯāh haṭṭôḇāh mimennāh</strong> — 'that Vashti may not come before King Ahasuerus, and that the king give her royal position to another who is better than she.'</p>",
    "20": "<p><strong>wənišmaʿ p̄iṯgām hammeleḵ ʾăšer-yaʿăśeh bəḵol-malkûṯô kî rabbāh hîʾ</strong> — 'And when the decree of the king is heard throughout all his kingdom, great as it is, all women will give honor to their husbands.' <em>P̄iṯgām</em> (H6599 = decree, word; a Persian loanword) — the technical term for a royal proclamation. The logic is social deterrence: publicizing the queen's punishment will discipline all married women in the empire. The phrase <em>kî rabbāh hîʾ</em> (for great it is) emphasizes the vastness of the empire, ensuring maximum distribution of the deterrent effect.</p>",
    "21": "<p><strong>wayyîṭaḇ haddāḇār bəʿênê hammeleḵ wəhaśśārîm</strong> — 'The plan pleased the king and the officials.' <em>Yāṭaḇ bəʿênê</em> (to be good in the eyes of; H3190 + H5869) — the idiom for approval/acceptance. The unanimity of approval — king and all officials — signals that Memucan's counsel was well-calibrated to the political moment. <strong>wayyaʿaś hammeleḵ kidəḇar Məmûḵān</strong> — 'and the king did according to the word of Memucan.' The counselor's word becomes the king's action — a pattern that will repeat with Haman's counsel in ch3 (with far more deadly consequences).</p>",
    "22": "<p><strong>wayyišlaḥ səp̄ārîm ʾel-kol-məḏînôṯ hammeleḵ</strong> — 'He sent letters to all the royal provinces.' The dispatch of letters throughout the 127 provinces is the Persian administrative mechanism for empire-wide decrees — the same mechanism that Haman will use for his genocide decree (3:13) and Mordecai and Esther will use for the counter-decree (8:9-14). <strong>ʾel-məḏînāh ûməḏînāh kiktāḇāh wəʾel-ʿam wāʿam kilšônô</strong> — 'to each province in its own script and to each people in its own language.' The multilingual decree distribution is a real feature of Persian imperial administration (confirmed by Aramaic, Elamite, Babylonian, and Old Persian versions of various royal documents). <strong>lihyôṯ kol-ʾîš śōrēr bəḇêṯô ûmədabbēr kilšôn ʿammô</strong> — 'that every man be master in his own house and speak the language of his own people.' The decree's content — domestic male authority and linguistic identity — is both an anti-Vashti measure and a statement about ethnic-linguistic identity that will become ironic when the Jews (who speak a different language) are targeted in ch3.</p>"
  },
  "2": {
    "1": "<p><strong>ʾaḥar haddəḇārîm hāʾēlleh kəšōḵ ḥămaṯ hammeleḵ ʾAḥašwērôš</strong> — 'After these things, when the wrath of King Ahasuerus had abated.' <em>Šāḵak</em> (H7918 = to be quieted, subside; same root as Jonah 1:11,12) — the anger diminishes with time. <strong>zāḵar ʾeṯ-waštî wəʾēṯ ʾăšer-ʿāśāṯāh wəʾēṯ ʾăšer-nigzar ʿālêhā</strong> — 'he remembered Vashti and what she had done and what had been decreed against her.' The verb <em>zāḵar</em> (H2142 = to remember, act on memory) — the key memory-verb of Esther (cf. 6:1-2 where the crucial act of remembrance saves Mordecai). Here the king's memory of Vashti opens the vacancy plot that will bring Esther into position.</p>",
    "2": "<p><strong>wayyōmərû naʿărê hammeleḵ məšārəṯāyw</strong> — 'The king's servants who attended him said.' The attendants' initiative — they volunteer a plan to solve the king's loneliness — is another instance of unnamed human agents moving the plot at precisely the right moment. <strong>yəḇaqqšû lammeleḵ nəʿārôṯ bəṯûlôṯ ṭôḇôṯ marʾeh</strong> — 'Let young women, virgins, of good appearance be sought for the king.' The terms: <em>nəʿārāh</em> (H5291 = young woman), <em>bəṯûlāh</em> (H1330 = virgin), <em>ṭôḇōṯ marʾeh</em> (H2896 + H4758 = good of appearance/looks). The beauty contest is the narrative mechanism for inserting Esther into the palace.</p>",
    "3": "<p><strong>weyap̄qēḏ hammeleḵ pəqîḏîm bəḵol-məḏînôṯ malkûṯô</strong> — 'And let the king appoint officials throughout all the provinces of his kingdom.' <em>Pāqaḏ pəqîḏîm</em> (appoint appointed-ones; the cognate accusative construction for emphasis) — formal administrative appointment. <strong>wiyqabbəṣû ʾeṯ-kol-naʿărāh-bəṯûlāh ṭôḇaṯ marʾeh ʾel-šûšan habbîrāh ʾel-bêṯ hannāšîm</strong> — 'and let them gather all the beautiful young virgins to Susa the citadel, to the harem (<em>bêṯ hannāšîm</em> = house of the women).' <em>Bêṯ hannāšîm</em> (H1004 + H802 = house of women) is the royal harem/seraglio. <strong>ʾel-yaḏ Hegay sərîs hammeleḵ šōmēr hannāšîm</strong> — 'under the custody of Hegai the king's eunuch, the keeper of the women.'</p>",
    "4": "<p><strong>wəhannaarāh ʾăšer tîṭaḇ bəʿênê hammeleḵ timlōḵ taḥaṯ-waštî</strong> — 'and the young woman who pleases the king shall be queen instead of Vashti.' The selection criterion is purely the king's pleasure — <em>ṭāḇ bəʿênê</em> (to be good in the eyes of) — no criteria of birth, politics, or merit are stated. The phrase 'instead of Vashti' ties this proposal directly to the deposition of ch1 and frames the entire ch2 narrative as filling the vacancy. <strong>wayyîṭaḇ haddāḇār bəʿênê hammeleḵ wayyaʿaś kēn</strong> — 'The plan pleased the king and he did so.' The same approval formula as 1:21 — the king implements what his attendants suggest, a pattern of reactive rather than proactive kingship.</p>",
    "5": "<p><strong>ʾîš yəhûḏî hāyāh bəšûšan habbîrāh ûšəmô Mordoḵay ben-Yāʾîr ben-Šimʿî ben-Qîš ʾîš yəmînî</strong> — 'There was a Jewish man in Susa the citadel, and his name was Mordecai son of Jair son of Shimei son of Kish, a Benjaminite.' The genealogy is precise: four generations are given. The name <em>Mordoḵay</em> (H4782) corresponds to the Babylonian name Mardukāya (from the god Marduk) — a diaspora name that does not indicate apostasy, as diaspora Jews regularly bore Babylonian names (Daniel, Hananiah, etc.). The Benjaminite identification is crucial: it aligns Mordecai with Saul's tribe (1 Sam 9:1 — Kish, a Benjaminite) and sets up the Agag/Haman conflict as a replay of the Saul-Agag encounter.</p>",
    "6": "<p><strong>ʾăšer hoglāh mîrûšālaim ʿim-haggōlāh ʾăšer-həglāṯāh ʿim Yəḵonyāh meleḵ-yəhûḏāh</strong> — 'who had been carried away from Jerusalem among the captives who had been taken into exile with Jeconiah king of Judah.' The relative clause clarifies the deportation context: the Babylonian exile of 597 BCE (the first major deportation under Nebuchadnezzar). <em>Hōglāh</em> and <em>həglāṯāh</em> use the same root <em>gālāh</em> (H1540 = to uncover, reveal, go into exile) — the double use emphasizes the exilic condition of Mordecai's family. Jeconiah (=Jehoiachin) was the king deported with the first major wave of Judean exiles (2 Kgs 24:14-15).</p>",
    "7": "<p><strong>wayhî ʾōmēn ʾeṯ-Hadassāh hîʾ ʾEsṯēr baṯ-dōḏô</strong> — 'He was raising Hadassah, that is Esther, his cousin's daughter.' Two names are given: <em>Hadassāh</em> (H1919 = myrtle, a Hebrew name) and <em>ʾEsṯēr</em> (H635 = possibly from Persian <em>stāra</em> = star, or from Babylonian Ishtar). The use of a Hebrew name and a Persian/Babylonian name mirrors Mordecai's own bicultural identity. <em>ʾōmēn</em> (H539, qal active participle = one who supports, raises; used of guardians, Num 11:12; 2 Kgs 10:1,5) describes Mordecai's parental role after the death of both her parents. <strong>kî ʾên lāh ʾāḇ wāʾem</strong> — 'for she had neither father nor mother' — the orphan status (<em>ʾên lāh ʾāḇ wāʾem</em>) is the ground for Mordecai's guardianship and his deep protectiveness throughout the narrative. <strong>wəhannaarāh yəp̄aṯ-tōʾar wəṭôḇaṯ marʾeh</strong> — 'the young woman had a beautiful figure and a good appearance' — the doubled beauty formula exactly matches that for Rachel (Gen 29:17, <em>yəp̄aṯ-tōʾar wîp̄aṯ marʾeh</em>) and Joseph (Gen 39:6, <em>yəp̄ēh-tōʾar wîp̄ēh marʾeh</em>), connecting Esther to the key providential-placement figures of Genesis.</p>",
    "8": "<p><strong>wayhî bəhiššāmaʿ dəḇar-hammeleḵ wədāṯô wəhiqqābēṣ nəʿārôṯ rabbôṯ ʾel-šûšan habbîrāh ʾel-yaḏ Hegay</strong> — 'When the king's edict and command were heard and many young women were gathered to Susa the citadel under Hegai's custody.' The passive <em>hiqqābēṣ</em> (niphal of <em>qābaṣ</em>, H6908 = to gather; here in the passive voice — 'were gathered') — Esther does not volunteer; she is gathered into the process. <strong>wattillāqaḥ ʾEsṯēr ʾel-bêṯ hammeleḵ ʾel-yaḏ Hegay šōmēr hannāšîm</strong> — 'And Esther was taken to the king's house under the custody of Hegai.' The passive <em>wattillāqaḥ</em> (she was taken) maintains the pattern of Esther as recipient of others' actions rather than initiator throughout ch2.</p>",
    "9": "<p><strong>wattiṭaḇ hannaarāh bəʿênāyw wayyiśśāʾ ḥesed ləp̄ānêhā</strong> — 'The young woman pleased him and she obtained kindness before him.' <em>Nāśāʾ ḥesed</em> (to carry/obtain kindness, H5375 + H2617) — the idiom for finding favor and loyalty; the object <em>ḥesed</em> (covenant loyalty, steadfast love) is notably weighty for a secular administrative context. <strong>waymahēr ʾeṯ-tamrûqêhā wəʾeṯ-mānôṯêhā lāṯēṯ lāh</strong> — 'and he quickly provided her with her ointments and her portions.' <em>Tāmrûq</em> (H8562 = ointment, cosmetic preparation for skin treatment; from <em>māraqqt</em> = to rub/scrape smooth) — the cosmetic preparations for the 12-month purification period (v12). Hegai's special favor means Esther receives preferential treatment from the beginning.</p>",
    "10": "<p><strong>lōʾ-higgîḏāh ʾEsṯēr ʾeṯ-ʿammāh wəʾeṯ-môladtāh</strong> — 'Esther had not revealed her people or her kindred.' Two nouns: <em>ʿam</em> (H5971 = people, ethnic group) and <em>môledet</em> (H4138 = birth, lineage, kindred). The concealment of identity is the first major narrative secret that drives the plot: the king does not know he has chosen a Jewess as queen. <strong>kî Mordoḵay ṣiwwāh ʿālêhā ʾăšer lōʾ-taggîḏ</strong> — 'for Mordecai had commanded her that she should not reveal it.' Mordecai's reason is not stated — the concealment may reflect general diaspora caution or specific knowledge of anti-Jewish sentiment in the court. The irony: the same concealment that endangers Esther (ch4 — who will speak for the Jews?) is also what gave her access to speak for them.</p>",
    "11": "<p><strong>ûḇəḵol-yôm wāyôm Mordoḵay miṯhalēḵ lip̄nê ḥăṣar bêṯ hannāšîm</strong> — 'And every day Mordecai walked in front of the court of the harem.' The distributive <em>bəḵol-yôm wāyôm</em> (every day and day) and the hithpael <em>miṯhalēḵ</em> (H1980, reflexive-iterative of <em>hālaḵ</em> = to walk/go — the walking back and forth) describe Mordecai's daily vigil. He walks the perimeter of the women's court to observe and receive reports. <strong>lādaʿaṯ ʾeṯ-šəlôm ʾEsṯēr</strong> — 'to know the welfare (<em>šālôm</em>, H7965) of Esther' — <em>šālôm</em> encompasses physical wellbeing, emotional state, and safety. The verb root <em>šālôm</em> will recur at the book's close (10:3 — Mordecai seeks the <em>šālôm</em> of all his people), creating a frame for the entire book.</p>",
    "12": "<p><strong>ûḇəhaggiʿa tōr naʿărāh wənaʿărāh lāḇôʾ ʾel-hammeleḵ ʾAḥašwērôš</strong> — 'When the turn of each young woman came to go to King Ahasuerus.' <em>Tōr</em> (H8447 = turn, order; from a root meaning to go in succession) — each young woman has her assigned turn in the rotation. <strong>miqqēṣ hĕyôṯ lāh kaḏāṯ hannāšîm šənêm ʿāśār ḥōḏeš</strong> — 'after being according to the rule for the women twelve months.' The 12-month cosmetic regimen is specified: <em>šiššāh ḥăḏāšîm bəšemen hammōr</em> (6 months with myrrh oil, H4753 = myrrh, the expensive aromatic resin) and <em>šiššāh ḥăḏāšîm babbəśāmîm ûḇətamrûqê hannāšîm</em> (6 months with spices and cosmetics). The preparation period emphasizes the resources invested in the selection process.</p>",
    "13": "<p><strong>ûḇāzeh hannaarāh bāʾāh ʾel-hammeleḵ</strong> — 'And in this way the young woman came to the king.' <strong>kōl ʾăšer-tōʾmar yinnāṯēn lāh lāḇôʾ ʿimmāh mibêṯ hannāšîm ʿaḏ-bêṯ hammeleḵ</strong> — 'Whatever she asked would be given her to take with her from the women's house to the king's house.' The provision: she may request any additional adornments or accessories she wishes for her presentation night. This provision creates a test of discernment — what a woman requests reveals her character and priorities.</p>",
    "14": "<p><strong>bāʿereḇ hîʾ ḇāʾāh ûḇabboqer hîʾ šāḇāh ʾel-bêṯ hannāšîm šēnî</strong> — 'In the evening she came and in the morning she returned to the second harem.' <em>Bêṯ hannāšîm šēnî</em> (the second women's house) — a separate quarter for the women who had appeared before the king but had not been selected as queen. They live in a kind of suspension: no longer eligible, not yet released. <strong>ʾel-yaḏ Šaʿašgaz sərîs hammeleḵ šōmēr happîlagšîm</strong> — 'under the custody of Shaashgaz the king's eunuch who kept the concubines.' <em>Pîlegeš</em> (H6370 = concubine) — the secondary-wife status that these women would carry; they were part of the king's household but could not return home or marry another.</p>",
    "15": "<p><strong>ûḇəhaggiʿa tōr-ʾEsṯēr baṯ-ʾAḇîḥayil ḏōḏ Mordoḵay ʾăšer lāqaḥ-lô ləḇaṯ</strong> — 'When the turn came for Esther daughter of Abihail the uncle of Mordecai, who had taken her as his daughter.' The full genealogical identification — daughter of Abihail, cousin of Mordecai, adopted as his daughter — appears at the moment of her entrance before the king; the family identity is preserved even as it is being concealed from the court. <strong>lōʾ biqqəšāh dāḇār</strong> — 'she did not ask for anything.' Esther's restraint contrasts implicitly with the other women's requests. She relied solely on Hegai's guidance and her own natural gifts — a wisdom that reflects Mordecai's counsel and her own discernment. <strong>wattəhî ʾEsṯēr nōśēʾṯ ḥēn bəʿênê kol-rōʾêhā</strong> — 'Esther was winning favor in the eyes of all who saw her.' <em>Nōśēʾṯ ḥēn</em> (carrying favor) — the habitual participle shows this was a consistent quality: wherever Esther went, she found favor.</p>",
    "16": "<p><strong>wattillāqaḥ ʾEsṯēr ʾel-hammeleḵ ʾAḥašwērôš ʾel-bêṯ malkûṯô</strong> — 'Esther was taken to King Ahasuerus, into his royal house.' <strong>bəḥōḏeš hāʿăśîrî hûʾ-ḥōḏeš ṭēḇēṯ bišnaṯ šeḇaʿ ləmalkûṯô</strong> — 'in the tenth month (that is, the month Tebeth) in the seventh year of his reign.' The date — month 10, year 7 — is four years after the events of ch1 (year 3). The gap between Vashti's removal and Esther's selection is not explained, leaving space for historical events (including Xerxes' campaign against Greece, 480-479 BCE) to fill.</p>",
    "17": "<p><strong>wayyeʾĕhaḇ hammeleḵ ʾeṯ-ʾEsṯēr mikkol-hannāšîm</strong> — 'The king loved Esther more than all the women.' <em>ʾāhaḇ</em> (H157 = to love) — the statement of royal love/preference is the strongest possible term; the comparison <em>mikkol-hannāšîm</em> (more than all the women) emphasizes uniqueness. <strong>wattissāʾ-ḥēn wāḥeseḏ ləp̄ānāyw mikkol-habbəṯûlôṯ</strong> — 'she obtained favor and kindness before him more than all the virgins.' The double favor — <em>ḥēn</em> (H2580 = grace, charm) and <em>ḥeseḏ</em> (H2617 = steadfast love, covenant loyalty) — marks the quality of Esther's reception. <strong>wayyāśem keter-malkûṯ bərōʾšāh wayyamlikēhā taḥaṯ waštî</strong> — 'he placed the royal crown on her head and made her queen instead of Vashti.' The coronation is described with one action — the crown placement — and one declaration.</p>",
    "18": "<p><strong>wayyaʿaś hammeleḵ mišṭeh gāḏôl ləḵol śārāyw waʿăḇāḏāyw mišṭēh ʾEsṯēr</strong> — 'Then the king made a great feast for all his officials and servants — the feast of Esther.' The naming of the feast after Esther (<em>mišṭēh ʾEsṯēr</em>) is unique; feasts are typically named after events or hosts, not recipients of honor. <strong>wahănāḥāh lammĕḏînôṯ ʿāśāh</strong> — 'and he gave a holiday to the provinces.' <em>Hănāḥāh</em> (H2010 = remission, holiday; a release from normal obligations) — tax relief or exemption as a royal celebratory gesture is attested in Persian sources.</p>",
    "19": "<p><strong>ûḇəhiqābēṣ bəṯûlôṯ šēnît</strong> — 'When the virgins were gathered a second time.' The parenthetical note about a second gathering of virgins is briefly mentioned without explanation — possibly indicating that the harem-selection process continued even after Esther's coronation, or that Mordecai's gate-sitting provided surveillance of an ongoing process. <strong>ûMordoḵay yōšēḇ bəšaʿar hammeleḵ</strong> — 'Mordecai was sitting at the king's gate.' <em>Yōšēḇ bəšaʿar hammeleḵ</em> (sitting in the king's gate) — the gate of the Persian palace was a governmental administrative space where officials transacted legal and political business. Mordecai's regular presence there suggests he held some official position, not merely loitering.</p>",
    "20": "<p><strong>ʾên ʾEsṯēr maggiḏāh môladtāh wəʾeṯ-ʿammāh kaʾăšer ṣiwwāh ʿālêhā Mordoḵay</strong> — 'Esther had not revealed her birth or her people, as Mordecai had commanded her.' The reminder of Esther's concealment at this point — just after her coronation — sets up the central crisis of ch4: she is queen, but the king does not know she is Jewish, and Mordecai's command to conceal her identity will need to be overridden precisely because the Jewish people need a known advocate before the king. <strong>kî-ʾEsṯēr ʿōśāh ʾeṯ-maʾămar Mordoḵay kaʾăšer hāyəṯāh bəʾāmōnāh ʾittô</strong> — 'for Esther followed the command of Mordecai as when she was raised by him.' <em>Bəʾāmōnāh</em> (H548 = as in her upbringing/guardianship; from <em>ʾāman</em>, to support, raise) — her adult obedience matches her childhood obedience under Mordecai's care.</p>",
    "21": "<p><strong>bayyāmîm hāhēm ûMordoḵay yōšēḇ bəšaʿar-hammeleḵ</strong> — 'In those days, while Mordecai was sitting at the king's gate.' The temporal phrase connects the assassination plot to the narrative of Mordecai's gate-presence — he discovers the plot precisely because he occupies the position where such information circulates. <strong>qāṣap̄ Bigṯān wāṯereš šənê sārîsê hammeleḵ miššōmərê hassap̄</strong> — 'Bigthana and Teresh, two of the king's eunuchs, the gatekeepers, became angry.' <em>Qāṣap̄</em> (H7107 = to be furious, wrathful) — their anger at the king is not explained; the unexplained grievance suggests it was known to the original readers. <strong>wayəḇaqqšû lišlōaḥ yāḏ bammeleḵ ʾAḥašwērôš</strong> — 'and they sought to lay hands on King Ahasuerus' — the euphemism for assassination.</p>",
    "22": "<p><strong>wayyiwwāḏaʿ haddāḇār ləMordoḵay wayyaggēḏ ləʾEsṯēr hammalkāh</strong> — 'The matter became known to Mordecai and he told Queen Esther.' The passive <em>wayyiwwāḏaʿ</em> (H3045, niphal = it became known) does not specify how Mordecai learned of the plot — a deliberate narrative vagueness that keeps the focus on the act of reporting rather than the intelligence source. <strong>wayyōmər ʾEsṯēr lammeleḵ bəšēm Mordoḵay</strong> — 'and Esther told the king in Mordecai's name.' Esther's intermediary role is explicit: she has access to the king; Mordecai does not. She transmits his information, preserving attribution — 'in Mordecai's name' means the credit will go to the proper source.</p>",
    "23": "<p><strong>wayyəḇuqqaš haddāḇār wayyimmāṣēʾ</strong> — 'The matter was investigated and found to be true.' The official investigation confirms the plot. <strong>wayyitlû šənêhem ʿal-ʿēṣ</strong> — 'Both were hanged on a gallows/tree.' <em>Tālāh ʿal-ʿēṣ</em> (H8518 + H6086 = to hang on the tree/stake) — the same combination used for Haman's execution in ch7 and his sons' display in ch9. The word <em>ʿēṣ</em> (tree, wood, stake) will become the book's execution motif. <strong>wayyikkāṯēḇ bəsēfer diḇrê hayyāmîm lip̄nê hammeleḵ</strong> — 'It was written in the book of the chronicles before the king.' The recording in the royal chronicles is the act that will matter six years later (ch6:1) when the king's sleeplessness leads him to have the chronicles read aloud.</p>"
  },
  "3": {
    "1": "<p><strong>ʾaḥar haddəḇārîm hāʾēlleh giḏdal hammeleḵ ʾAḥašwērôš ʾeṯ-Hāmān</strong> — 'After these things King Ahasuerus promoted Haman.' <em>Giḏdal</em> (H1431, piel = to make great, elevate) — Haman's elevation is an act of royal initiative, not Haman's own ambition (at this point). <strong>ben-Hammedāṯāʾ hāʾăgāgî</strong> — 'son of Hammedatha the Agagite.' The Agagite designation (<em>hāʾăgāgî</em>, H91) connects Haman to Agag king of Amalek (1 Sam 15:8-9), whose survival Saul was condemned for sparing. The Agagite identification marks Haman as the perpetual enemy of Israel — the Amalekite threat reappearing in the diaspora. <strong>wayyārem ʾeṯ-kissəʾô mēʿal kol-haśśārîm ʾăšer ʾittô</strong> — 'and set his seat above all the officials who were with him.' The imagery of the elevated seat — the physical placement above all others — establishes Haman as the king's second-in-command and sets up the prostration requirement.</p>",
    "2": "<p><strong>wəḵol-ʿaḇdê hammeleḵ ʾăšer-bəšaʿar hammeleḵ kōrəʿîm ûmišṭaḥăwîm ləHāmān</strong> — 'All the king's servants who were at the king's gate bowed down and prostrated themselves before Haman.' <em>Kāraʿ</em> (H3766 = to kneel, bow the knee) and <em>šāḥāh</em> (H7812, hishtaphel = to bow down, prostrate oneself) — the paired verbs for full prostration, the maximum physical expression of submission. <strong>kî-ḵēn ṣiwwāh-lô hammeleḵ</strong> — 'for so the king had commanded regarding him.' The prostration is a royal command, not voluntary custom; Mordecai's refusal is therefore technically a violation of royal decree. <strong>ûMordoḵay lōʾ yikraʿ wəlōʾ yišṭaḥăweh</strong> — 'but Mordecai would not bow or prostrate himself.' The two negated verbs (<em>lōʾ yikraʿ wəlōʾ yišṭaḥăweh</em>) match the two positive verbs describing the other servants' compliance — a precise literary contrast.</p>",
    "3": "<p><strong>wayyōmərû ʿaḇdê hammeleḵ ʾăšer-bəšaʿar hammeleḵ ləMordoḵay</strong> — 'The king's servants who were at the king's gate said to Mordecai.' The other servants challenge Mordecai's non-compliance — they are not sympathizers but fellow servants concerned about the collective implications of one person's refusal. <strong>madduaʿ ʾattāh ʿôḇēr ʾeṯ miṣwaṯ hammeleḵ</strong> — 'Why are you transgressing the king's command?' <em>ʿāḇar miṣwat</em> (H5674 + H4687 = to cross/transgress a commandment) — the language of covenant violation used in a secular administrative context, showing that the royal command has quasi-legal weight.</p>",
    "4": "<p><strong>wayhî baʾomrām ʾēlāyw yôm wāyôm wəlōʾ šāmaʿ ʾălêhem</strong> — 'And when they spoke to him daily and he would not listen to them.' The iterative <em>yôm wāyôm</em> (day by day) — the pressure was sustained and repeated; Mordecai's refusal was not a one-time lapse but a consistent policy. <strong>wayyaggîḏû ləHāmān lirʾôṯ hăyaʿamḏû diḇrê Mordoḵay kî-higgîḏ lāhem ʾăšer-hûʾ yəhûḏî</strong> — 'they told Haman, to see whether Mordecai's words would stand, for he had told them that he was a Jew.' The disclosure of Mordecai's Jewish identity is what transforms a refusal of prostration into an ethnic-religious incident. Mordecai himself gave the reason for his non-compliance: he is a Jew.</p>",
    "5": "<p><strong>wayyarʾ Hāmān kî-ʾên Mordoḵay kōrēaʿ ûmišṭaḥăweh lô</strong> — 'When Haman saw that Mordecai did not bow or prostrate himself before him.' Haman's personal observation confirms what he has been told. <strong>wayyimmālēʾ Hāmān ḥēmāh</strong> — 'Haman was full of wrath' — <em>mālaʾ ḥēmāh</em> (to be filled with burning anger, H4390 + H2534) — the idiom of being filled with wrath suggests an overwhelming, all-consuming emotion. The contrast: Haman is 'full' of wrath in the same way Esther will later be 'full' of favor — the same filling-metaphor applied to opposite moral qualities.</p>",
    "6": "<p><strong>wayyiḇez bəʿênāyw lišlōaḥ yāḏ bəMordoḵay bəlaḏḏô</strong> — 'But he disdained to lay his hand on Mordecai alone.' <em>Bāzāh bəʿênāyw</em> (to be contemptible in one's eyes; H959 = to despise) — the same verb used of Vashti's deed being contemptible (1:17). Haman considers individual revenge beneath him. <strong>kî-higgîḏû lô ʾeṯ-ʿam Mordoḵay</strong> — 'for they had told him Mordecai's people.' The scale of the retaliation — targeting all Jews in the empire — is motivated by ethnic identification: Mordecai represents his people, and Haman will destroy them all. <strong>wayəḇaqqēš Hāmān ləhašmîḏ ʾeṯ-kol-hayyəhûḏîm ʾăšer bəḵol-malkûṯ ʾAḥašwērôš</strong> — 'and Haman sought to destroy all the Jews who were throughout all the kingdom of Ahasuerus.' The three-term destruction formula begins here: <em>lhašmîḏ</em> (H8045 = to destroy utterly) is the first of three destruction verbs used throughout the book.</p>",
    "7": "<p><strong>baḥōḏeš hāriʾšôn hûʾ-ḥōḏeš nîsān bišnaṯ šeṯêm ʿeśrēh ləmeleḵ ʾAḥašwērôš</strong> — 'In the first month, that is the month of Nisan, in the twelfth year of King Ahasuerus.' The date is precisely year 12 of Ahasuerus; Esther became queen in year 7 (2:16), so five years have elapsed. <strong>hippîl pûr hûʾ-haggôrāl lip̄nê Hāmān ləḵol-yôm wəlāḥōḏeš šənêm ʿāśār hûʾ-ḥōḏeš ʾăḏār</strong> — 'Pur — that is, the lot — was cast before Haman for every day and every month, until the twelfth month, that is the month Adar.' <em>Pûr</em> (H6332) is an Akkadian loanword for lot/die; the parenthetical gloss <em>hûʾ-haggôrāl</em> (that is, the lot) translates the Akkadian into Hebrew for the reader. The lot falls on Adar (month 12), giving the Jews approximately eleven months' warning — time for Mordecai and Esther's intervention.</p>",
    "8": "<p><strong>wayyōʾmer Hāmān lammeleḵ ʾAḥašwērôš yešnô ʿam-ʾeḥāḏ məp̄uzzār ûməp̄ōrāḏ bên hāʿammîm bəḵol məḏînôṯ malkûṯeḵā</strong> — 'And Haman said to King Ahasuerus: There is a certain people scattered and separated among the peoples in all the provinces of your kingdom.' <em>Məp̄uzzār ûməp̄ōrāḏ</em> (scattered and separated; H6340 + H6504, pual participles — passive: they have been scattered and are divided) — both terms are passive, describing the Jewish diaspora as a dispersed and fragmented presence throughout the empire. <strong>wədāṯêhem šōnôṯ mikkol-ʿām</strong> — 'and their laws are different from those of every other people.' The charge: legal distinctiveness. <em>Dāṯ</em> (H1881 = law, custom) — Haman uses the Persian administrative term for law to characterize the Jews' Torah observance as anti-imperial non-conformity.</p>",
    "9": "<p><strong>wəʾeṯ-dāṯê hammeleḵ ʾênām ʿōśîm</strong> — 'and the laws of the king they do not obey.' This is the climax of Haman's political charge: the Jews are loyal to their own legal system above the king's decrees — an existential claim against a minority within a totalitarian empire. <strong>wəlammeleḵ ʾên šōweh ləhannîḥām</strong> — 'and it is not to the king's profit to tolerate them.' <em>Šāweh</em> (H7737 = to be comparable, equivalent, worth it) — the cost-benefit framing: the Jews cost more in disruption than they contribute. <strong>ʾim-ʿal-hammeleḵ ṭôḇ yikkāṯēḇ ləʾabbəḏām waʿăśereṯ ʾălāp̄îm kikkār-kesef ʾeššāqôl ʿal-yədê ʿōśê hammālāʾḵāh lhāḇîʾ ʾel-gizzê hammeleḵ</strong> — 'if it pleases the king, let it be written to destroy them, and I will pay ten thousand talents of silver... into the king's treasury.' 10,000 talents (an almost unimaginable sum — far exceeding annual imperial revenue) is Haman's bribe for royal compliance.</p>",
    "10": "<p><strong>wayyāsar hammeleḵ ʾeṯ-ṭabbaʿtô mēʿal yāḏô wayyittənāh ləHāmān</strong> — 'The king removed his signet ring from his hand and gave it to Haman.' <em>Ṭabbaʿat</em> (H2885 = signet ring; from <em>ṭāḇaʿ</em> = to seal/imprint) — the ring that seals official royal documents. The transfer of the signet ring is the transfer of royal executive authority. <strong>ben-Hammedāṯāʾ hāʾăgāgî ṣōrēr hayyəhûḏîm</strong> — 'son of Hammedatha the Agagite, the enemy of the Jews.' The epithet <em>ṣōrēr hayyəhûḏîm</em> (H6887 = adversary, one who presses/binds the Jews) functions as a permanent appellation — every subsequent reference to Haman is accompanied by this title.</p>",
    "11": "<p><strong>wayyōʾmer hammeleḵ ləHāmān hakkesep̄ nāṯûn lāḵ wəhāʿām laʿăśôṯ bô kaṭṭôḇ bəʿênêḵā</strong> — 'The king said to Haman: The silver is given to you, and the people also, to do with as seems good to you.' The king's casual grant of genocide is one of the most chilling moments in the book: no inquiry, no confirmation of the charges — a minority population is handed over to its enemy's disposal for ten thousand talents. The phrase <em>kaṭṭôḇ bəʿênêḵā</em> (as seems good to your eyes) grants Haman absolute discretion.</p>",
    "12": "<p><strong>wayyiqqārəʾû sōp̄ərê hammeleḵ baḥōḏeš hāriʾšôn bišlōšāh ʿāśār yôm bô</strong> — 'The king's scribes were summoned on the thirteenth day of the first month.' The scribes (<em>sōp̄ərîm</em>, H5608) are the professional document-writers of the Persian court. The date — 13 Nisan — gives the decree its timestamp; the decree specifies the execution date as 13 Adar (month 12), giving eleven months of forewarning in which the counter-narrative of chs 4-8 unfolds. <strong>wayyikkāṯēḇ kəḵol-ʾăšer-ṣiwwāh Hāmān</strong> — 'and it was written according to all that Haman commanded' — Haman composes; the scribes write; the king seals. The three-stage process of imperial decree-making is complete.</p>",
    "13": "<p><strong>wənišlôaḥ səp̄ārîm bəyaḏ hārāṣîm ʾel-kol-məḏînôṯ hammeleḵ</strong> — 'Letters were sent by couriers to all the king's provinces.' The distribution mechanism — royal couriers (<em>rāṣîm</em>, H7323 = runners, those who speed on foot) — is the Persian imperial postal system. <strong>ləhašmîḏ lahărōg ûləʾabbēḏ ʾeṯ-kol-hayyəhûḏîm minnaarûménaʿar wəʿaḏ-zāqēn ṭap̄ wənāšîm bəyôm ʾeḥāḏ</strong> — 'to destroy, to kill, and to annihilate all Jews, young and old, children and women, in one day.' The three-fold destruction formula (<em>lhašmîḏ lahărōg ûləʾabbēḏ</em>) with the total demographic enumeration (young and old, children and women) describes complete genocide. <strong>ûšəlālām lāḇôz</strong> — 'and to plunder their goods.' The economic motive — plunder — is added as incentive for the executors.</p>",
    "14": "<p><strong>paṯšegen hakkəṯāḇ lhinnāṯen dāṯ bəḵol-məḏînāh ûməḏînāh</strong> — 'A copy of the edict was to be issued as law in every province.' <em>Paṯšegen</em> (H6572 = copy, transcript; a Persian loanword) — the distributed copies function as binding law throughout the empire. <strong>gālûy ləḵol-hāʿammîm lihyôṯ ʿăṯûḏîm layyôm hazzeh</strong> — 'proclaimed to all peoples so that they should be ready for that day.' <em>ʿĀṯûḏîm</em> (H6264 = prepared, ready) — the peoples are being prepared as executors of the genocide, not merely informed of it.</p>",
    "15": "<p><strong>hārāṣîm yaṣəʾû ḏəḥûp̄îm bidiḇar hammeleḵ</strong> — 'The couriers went out hurriedly by order of the king.' <em>Dəḥûp̄îm</em> (H1765 = pressed, hurried) — urgency in the distribution. <strong>wəhaddāṯ nittənāh bəšûšan habbîrāh</strong> — 'and the edict was issued in Susa the citadel.' <strong>wəhammeleḵ wəHāmān yāšəḇû lišṯôṯ</strong> — 'and the king and Haman sat down to drink.' The casual post-decree drinking is a deliberate narrative contrast: imperial power casually dispatching genocide and then returning to its wine. <strong>wəhāʿîr šûšān nāḇôḵāh</strong> — 'but the city of Susa was thrown into confusion.' <em>Nāḇôḵ</em> (H943, niphal = to be confused, bewildered) — the city's corporate distress contrasts with the king and Haman's equanimity; the people of Susa know something terrible has been unleashed, even if they cannot yet see the full scope.</p>"
  },
  "4": {
    "1": "<p><strong>ûMordoḵay yāḏaʿ ʾeṯ-kol-ʾăšer naʿăśāh</strong> — 'When Mordecai knew all that had been done.' The verb <em>yāḏaʿ</em> (H3045 = to know, come to know) with its object <em>kol-ʾăšer naʿăśāh</em> (all that had been done) — Mordecai receives complete information about the decree. <strong>wayyiqraʿ Mordoḵay ʾeṯ-bəgāḏāyw wayyilbêš śaq wāʾēper</strong> — 'Mordecai tore his clothes and put on sackcloth and ashes.' The mourning rites: tearing of garments (<em>qāraʿ bəgāḏîm</em>, H7167), wearing sackcloth (<em>śaq</em>, H8242 = rough goat-hair fabric worn in mourning), and ashes (<em>ʾēper</em>, H665 = ash; placed on the head as a symbol of grief and mortality). This triple mourning act is the traditional Hebrew expression of extreme grief (cf. 2 Sam 13:19; Joel 1:13; Jonah 3:6-8).</p>",
    "2": "<p><strong>wayyāḇôʾ ʿaḏ-lip̄nê šaʿar hammeleḵ kî ʾên lāḇôʾ ʾel-šaʿar hammeleḵ bilḇûš śāq</strong> — 'He came as far as before the king's gate, for no one was permitted to enter the king's gate in sackcloth.' The prohibition on mourning garments at the palace gate is a Persian custom attested in Herodotus (3.117) and other sources: the king's presence could not be approached with signs of distress, which might pollute the royal space or offend the royal dignity. Mordecai presses as close as permitted — to the gate's entrance — in his public mourning.</p>",
    "3": "<p><strong>ûḇəḵol-məḏînāh ûməḏînāh məqôm ʾăšer diḇar-hammeleḵ wədāṯô maggîaʿ ʾēḇel gāḏôl layyəhûḏîm</strong> — 'In each and every province, wherever the king's word and his edict reached, there was great mourning among the Jews.' The universal distribution of grief mirrors the universal distribution of the edict: the decree reaches every province, and in every province Jews respond with mourning. <strong>wəṣôm ûḇəḵî ûmisĕpēḏ śaq wāʾēper yussaḏ lārabbîm</strong> — 'fasting, weeping, lamenting; sackcloth and ashes were spread among the multitudes.' The four mourning practices — <em>ṣôm</em> (H6685 = fasting), <em>bāḵāh</em> (H1058 = weeping), <em>sāp̄aḏ</em> (H5594 = lamenting/wailing), and the material symbols of sackcloth/ashes — constitute the full ritual of communal grief.</p>",
    "4": "<p><strong>watābōʾʾnāh naarôṯ ʾEsṯēr wəsārîsêhā wayyaggîḏû lāh</strong> — 'Esther's attendants and eunuchs came and told her.' Esther receives the report of Mordecai's mourning through her palace staff — she is insulated from the outside world by the court's physical barriers. <strong>wattitḥalḥal hammalkāh məʾōḏ</strong> — 'the queen was greatly distressed.' <em>Ḥālaḥ</em> (H2342, hitpalpel = to writhe, be in anguish; the intensive reflexive form) — physical anguish at the news. <strong>wattišlaḥ bəgāḏîm lhalbîš ʾeṯ-Mordoḵay ûlhāsîr śaqqô mēʿālāyw</strong> — 'she sent garments to clothe Mordecai and remove his sackcloth from him.' The attempt to dress Mordecai in court clothing — to restore normalcy — is rejected: <strong>wəlōʾ qibbēl</strong> — 'but he did not accept.' Mordecai's mourning is deliberate, not incidental; he refuses normalization.</p>",
    "5": "<p><strong>wattiqqrāʾ ʾEsṯēr lHăṯāḵ</strong> — 'Then Esther called Hathach.' Hathach is a eunuch assigned to Esther's service — her trusted intermediary who will carry messages between her and Mordecai. <strong>ûltəṣawwêhû ʿal-Mordoḵay lāḏaʿaṯ māh-zeh wəʿal-mah-zeh</strong> — 'and commanded him to go to Mordecai to find out what this was and why.' The doubled interrogative <em>māh-zeh wəʿal-mah-zeh</em> (what this is and why) — Esther needs both the information and the reason for it before she can respond.</p>",
    "6": "<p><strong>wayyēṣēʾ Hăṯāḵ ʾel-Mordoḵay ʾel-rəḥôḇ hāʿîr</strong> — 'So Hathach went out to Mordecai in the open square of the city.' <em>Rəḥôḇ hāʿîr</em> (H7339 + H5892 = the broad place of the city, the city square) — the public space in front of the king's gate where Mordecai has positioned himself in full mourning, visible to everyone. The choice of location is itself a public act: Mordecai will not go unobserved.</p>",
    "7": "<p><strong>wayyaggēḏ-lô Mordoḵay ʾēṯ kol-ʾăšer qārāhû</strong> — 'Mordecai told him all that had happened to him' — the full account of Haman's scheme and the payment amount. <strong>wəʾeṯ parāšat hakkesep̄ ʾăšer ʾāmar Hāmān lišqôl ʿal-gizzê hammeleḵ bayyəhûḏîm ləʾabbəḏām</strong> — 'and the exact sum of money that Haman had promised to pay to the king's treasury for the destruction of the Jews.' <em>Parāšat hakkesep̄</em> (the specification of the silver) — the financial detail (10,000 talents) is transmitted precisely; Mordecai wants Esther to understand the scale of the transaction.</p>",
    "8": "<p><strong>wəʾeṯ-paṯšegen kəṯāḇ-haddāṯ ʾăšer-niṯan bəšûšān lhašmîḏām nāṯan lô</strong> — 'He also gave him a copy of the written decree for their destruction that was issued in Susa.' The physical copy of the decree — <em>paṯšegen kəṯāḇ-haddāṯ</em> (a copy of the written law/decree, using the Persian loanword again) — is given to Hathach to show Esther. Documentary evidence, not just verbal report, is provided. <strong>lhare ʾĕsṯēr ûləhaggîḏ lāh ûlēṣawwôṯāh lāḇôʾ ʾel-hammeleḵ ləḥannānô ûlbaqqēš mimmennû ʿal-ʿammāh</strong> — 'to show Esther, tell her, and command her to go to the king to implore his favor and petition him on behalf of her people.' Mordecai's threefold instruction: show, tell, command — the verbs escalate from informational to imperatival.</p>",
    "9": "<p><strong>wayyāḇôʾ Hăṯāḵ wayyaggēḏ ləʾEsṯēr ʾeṯ diḇrê Mordoḵay</strong> — 'Hathach went and told Esther the words of Mordecai.' The faithful transmission: the intermediary reports exactly what he was given. The narrative moves quickly through the logistics to arrive at Esther's crucial decision in vv10-16.</p>",
    "10": "<p><strong>watōʾmer ʾEsṯēr ləHăṯāḵ</strong> — 'Esther spoke to Hathach.' The reverse transmission begins: Esther sends her reply back through the intermediary. <strong>wattəṣawwêhû ʾel-Mordoḵay</strong> — 'and commanded him to reply to Mordecai.' The verb <em>ṣiwwāh</em> (H6680 = to command, give instructions) — Esther issues instructions to her trusted eunuch with the authority of her queenly position, even in this private communication channel.</p>",
    "11": "<p><strong>kol-ʿaḇdê hammeleḵ wəʿam məḏînôṯ hammeleḵ yōḏəʿîm</strong> — 'All the king's servants and the people of the king's provinces know.' Esther grounds her response in the known legal reality. <strong>ʾăšer kol-ʾîš wəʾiššāh ʾăšer-yāḇôʾ ʾel-hammeleḵ ʾel-heḥāṣēr happənîmîṯ ʾăšer lōʾ-yiqqārēʾ ʾaḥaṯ dāṯô lhāmîṯ</strong> — 'that for any man or woman who enters the king's inner court without being called, there is one law: put to death.' The law of the inner court: one law (<em>ʾaḥaṯ dāṯô</em> = one decree for him/her) — death — applies universally to uninvited entry. The <em>ḥāṣēr happənîmîṯ</em> (inner court) is the sacred space around the throne; entry without invitation was a capital offense in Persian court protocol (cf. Herodotus 3.118, 140). <strong>lûlēʾ ʾăšer yôšîṭ-lô hammeleḵ ʾeṯ-šarḇîṭ hazzāhāḇ wāḥāy</strong> — 'unless the king extends to him the golden scepter, so that he may live.' The scepter extension is the king's prerogative of pardon/welcome — without it, the intruder dies. <strong>wăʾănî lōʾ niqrēʾṯî lāḇôʾ ʾel-hammeleḵ zeh šəlōšîm yôm</strong> — 'and I have not been called to come to the king for these thirty days.' The thirty-day gap between royal summons is Esther's personal datum that makes her approach even more dangerous: she has not been in the king's presence for a month — she cannot know his current mood toward her.</p>",
    "12": "<p><strong>wayyaggîḏû ləMordoḵay ʾeṯ diḇrê ʾEsṯēr</strong> — 'They told Mordecai Esther's words.' The plural <em>wayyaggîḏû</em> (they told) suggests Hathach is accompanied by others in the communication chain, or that multiple palace servants are involved in the message relay. Mordecai receives Esther's explanation of the legal barrier to her intervention.</p>",
    "13": "<p><strong>wayyōʾmer Mordoḵay lhāšîḇ ʾel-ʾEsṯēr</strong> — 'Mordecai told them to reply to Esther.' <strong>ʾal-tedammî bənap̄šēḵ lhimmālēṭ bêṯ-hammeleḵ mikkol-hayyəhûḏîm</strong> — 'Do not imagine (<em>dāmāh</em>, H1819 = to think, imagine, suppose) in your soul/self that you will escape in the king's palace more than all the Jews.' Mordecai's counterargument: the palace is not a sanctuary from the decree. Esther's Jewish identity — concealed from the king — is not concealed from Haman's agents; her palace location does not make her safe.</p>",
    "14": "<p><strong>kî ʾim-haḥărēš taḥărîšî bāʿēṯ hazzōʾṯ</strong> — 'For if you keep silent at this time.' <em>Hāraš taḥărîšî</em> — the emphatic construction with the infinitive absolute of <em>ḥārāš</em> (H2790 = to be silent, hold the tongue) + the finite verb: absolute, prolonged silence. <strong>rēwaḥ wəhaṣṣālāh yaʿămōḏ layyəhûḏîm mimmāqôm ʾaḥēr</strong> — 'relief and deliverance will arise for the Jews from another place.' <em>Rēwaḥ wəhaṣṣālāh</em> (relief and deliverance; H7305 = breathing-space/relief + H2020 = deliverance/escape) — Mordecai's conviction that the Jews will be saved regardless: divine preservation will come through one channel or another. This is the book's closest approach to a theological claim about providence — unnamed but unmistakable. <strong>wəʾaṯ ûḇêṯ-ʾāḇîḵ tōʾḇēḏû</strong> — 'and you and your father's house will perish.' If Esther chooses silence, she will not escape — she and her family will be destroyed along with the people she failed to help. <strong>ûmî yôḏēaʿ ʾim-ləʿēṯ kāzōʾṯ higgaʿṯ lammalkûṯ</strong> — 'And who knows whether you have not come to the kingdom for such a time as this?' <em>Mî yôḏēaʿ</em> (who knows?) — the rhetorical question that opens into the book's deepest theological moment: the possibility that Esther's entire life journey — orphaned, raised by Mordecai, selected in the beauty contest, placed before the king — was divinely ordered for this specific crisis.</p>",
    "15": "<p><strong>watōʾmer ʾEsṯēr lhāšîḇ ʾel-Mordoḵay</strong> — 'Then Esther told them to reply to Mordecai.' The shift in Esther's posture is expressed narratively rather than psychologically: the verbs change from explaining the barrier (v11) to issuing instructions (v15). The passive-reactive queen becomes an active strategist in one sentence.</p>",
    "16": "<p><strong>lēḵ kənōs ʾeṯ-kol-hayyəhûḏîm hannimsəʾîm bəšûšān</strong> — 'Go, assemble all the Jews who are found in Susa.' <em>Kānôs</em> (H3664, qal = to gather, assemble) — Esther issues her own command to Mordecai, reversing the flow of authority. <strong>wəṣûmû ʿālay wəʾal-tōʾḵəlû wəʾal-tišṯû šəlōšeṯ yāmîm lalyāh wāyôm</strong> — 'Fast for me, and do not eat or drink for three days, night or day.' The three-day total fast — no food or water for 72 hours — is more severe than the standard Yom Kippur fast; it is a fast of desperation and maximum petition. <strong>gam-ʾănî wənaʿărōṯay ʾāṣûm kēn</strong> — 'I and my maids will also fast accordingly.' Esther includes herself and her household — the fast is communal, not just requested of others. <strong>ûḇəḵēn ʾāḇôʾ ʾel-hammeleḵ ʾăšer lōʾ-ḵaddāṯ</strong> — 'And thus I will go to the king, which is against the law.' <em>ʾAšer lōʾ-ḵaddāṯ</em> (which is not according to the law) — Esther openly acknowledges that her planned action is illegal. <strong>waʾăšer ʾāḇadtî ʾāḇadtî</strong> — 'and if I perish, I perish.' The famous phrase: <em>ḵaʾăšer ʾāḇadtî ʾāḇadtî</em> — the two identical verb forms (qal perfect first person singular of <em>ʾāḇaḏ</em>, H6) create a resigned acceptance: 'if I am destroyed, I am destroyed.' Not fatalism but determination that accepts the ultimate cost. This is the narrative's moral apex: Esther moves from self-protection to self-sacrifice.</p>",
    "17": "<p><strong>wayyaʿăḇōr Mordoḵay wayyaʿaś kəḵōl ʾăšer-ṣiwwəṯāh ʿālāyw ʾEsṯēr</strong> — 'Mordecai went away and did all that Esther had commanded him.' The reversal is complete: in chs 1-3 Mordecai gave commands and Esther obeyed (2:10, 20); now Esther commands and Mordecai obeys. The authority structure has shifted; Esther has taken leadership of the plan to save her people.</p>"
  },
  "5": {
    "1": "<p><strong>wayhî bayyôm haššəlîšî wattilbēš ʾEsṯēr malkûṯ</strong> — 'On the third day Esther put on her royal robes.' <em>Bayyôm haššəlîšî</em> (on the third day) — the three-day fast (4:16) has concluded; Esther rises on the third day. <em>Lāḇaš malkûṯ</em> (H3847 + H4438 = clothe with royalty; put on royal things) — the phrase means Esther dressed in her full royal regalia, not merely ordinary clothing. <strong>wattaʿămōḏ baḥăṣar bêṯ-hammeleḵ happənîmîṯ</strong> — 'and stood in the inner court of the king's house.' The spatial movement is precisely the legal threshold she described in 4:11 — the inner court (<em>ḥāṣēr happənîmîṯ</em>) where uninvited entry was punishable by death. <strong>nōḵaḥ bêṯ hammeleḵ</strong> — 'facing the king's hall' — positioned so the king would see her from his throne.</p>",
    "2": "<p><strong>wayhî kirʾôṯ hammeleḵ ʾeṯ-ʾEsṯēr hammalkāh ʿōmeḏeṯ beḥāṣēr</strong> — 'When the king saw Queen Esther standing in the court.' The king's sight of Esther — the moment of maximum narrative tension — is expressed simply: he looks and he sees. <strong>nāśāʾ ḥēn bəʿênāyw</strong> — 'she found favor in his eyes' — <em>nāśāʾ ḥēn</em> (obtained favor) is the same idiom used of Esther's reception by Hegai (2:9) and the whole population (2:15) — the phrase that has characterized her experience throughout. In this moment, the same favor that has protected her in the harem now protects her at the threshold of death. <strong>wayyôšeṭ hammeleḵ ləʾEsṯēr ʾeṯ-šarḇîṭ hazzāhāḇ ʾăšer bəyāḏô</strong> — 'The king extended the golden scepter that was in his hand to Esther.' The scepter (<em>šarḇîṭ</em>, H8275 = scepter, staff of office; a Persian loanword) extended is the formal signal of welcome; the capital offense is pardoned. <strong>waṯiggaš ʾEsṯēr wattiddaʿ bərōʾš haššarḇîṭ</strong> — 'and Esther approached and touched the tip of the scepter.' The physical touch of the scepter's tip completes the act of entry; Esther is now inside the legal circle of royal welcome.</p>",
    "3": "<p><strong>wayyōʾmer lāh hammeleḵ māh-lāḵ ʾEsṯēr hammalkāh</strong> — 'The king said to her: What is it, Queen Esther?' The king's question uses her full title — Queen Esther — marking the official, formal nature of the encounter. <strong>ûmah-baqqāšāṯēḵ ʿaḏ-ḥăṣî hammalkûṯ weyinnāṭen lāḵ</strong> — 'and what is your request? Up to half the kingdom, it shall be given to you.' The royal generosity formula (<em>ʿaḏ-ḥăṣî hammalkûṯ</em>) appears for the first time — a conventional hyperbole of Persian royal magnanimity. The irony will be that Esther's request is not for territory or wealth but for lives, which requires reversing an irrevocable decree.</p>",
    "4": "<p><strong>watōʾmer ʾEsṯēr ʾim-ʿal-hammeleḵ ṭôḇ yāḇôʾ hammeleḵ wəHāmān hayyôm</strong> — 'Esther said: If it pleases the king, let the king and Haman come today.' Esther's first request is not a petition but an invitation: she does not immediately disclose her purpose but instead requests the king and Haman come to a banquet she has prepared. The strategic delay is the subject of much commentary: perhaps Esther was testing the king's mood, or securing Haman's presence at a controlled location, or following a divinely-prompted strategy. <strong>ʾel-hammišṭeh ʾăšer-ʿāśîṯî lô</strong> — 'to the banquet I have prepared for him' — the king is the guest of honor, not Haman; but Haman is summoned alongside, setting the stage for his exposure.</p>",
    "5": "<p><strong>wayyōʾmer hammeleḵ mahărû ʾeṯ-Hāmān laʿăśôṯ ʾeṯ-diḇar ʾEsṯēr</strong> — 'The king said: Bring Haman quickly to do Esther's word.' <em>Māhar</em> (H4116 = to hasten, be quick) — the king's immediate compliance with Esther's banquet invitation signals that his disposition toward her is favorable. <strong>wayyāḇôʾ hammeleḵ wəHāmān ʾel-hammišṭeh ʾăšer ʿāśəṯāh ʾEsṯēr</strong> — 'and the king and Haman came to the banquet that Esther had prepared.'</p>",
    "6": "<p><strong>wayyōʾmer hammeleḵ ləʾEsṯēr bəmišṭēh hayyāyin</strong> — 'The king said to Esther at the wine banquet.' <em>Mišṭēh hayyāyin</em> (H4960 + H3196 = the drinking feast of wine) — the specific phrase for the wine-drinking portion of the banquet, after the meal. <strong>māh šəʾēlāṯēḵ wəyinnāṭen lāḵ ûmah baqqāšāṯēḵ ʿaḏ-ḥăṣî hammalkûṯ wəṯēʿāś</strong> — 'What is your petition and it will be granted; what is your request, up to half the kingdom, and it shall be done.' The formula repeats; the king's generosity is again on offer. This second invocation of the 'half the kingdom' formula (after v3) creates double expectation that Esther will now make her real request.</p>",
    "7": "<p><strong>wattagʿan ʾEsṯēr watōʾmar šəʾēlāṯî ûḇaqqāšāṯî</strong> — 'Esther answered and said: My petition and request is.' The beginning of Esther's answer sounds like she is finally going to make her disclosure — but she delays again: <strong>ʾim-māṣāʾṯî ḥēn bəʿênê hammeleḵ wəʾim-ʿal-hammeleḵ ṭôḇ lāṯēṯ ʾeṯ-šəʾēlāṯî ûlaʿăśôṯ ʾeṯ-baqqāšāṯî</strong> — 'If I have found favor in the king's eyes and if it pleases the king to grant my petition and fulfill my request.' The double condition preamble — <em>ʾim-māṣāʾṯî ḥēn... wəʾim-ʿal-hammeleḵ ṭôḇ</em> — echoes the deferential formulas of 4:8 and the standard petition format. But instead of the petition itself, another banquet invitation follows (v8).</p>",
    "8": "<p><strong>yāḇôʾ hammeleḵ wəHāmān ʾel-hammišṭeh ʾăšer-ʾeʿĕśeh lāhem</strong> — 'Let the king and Haman come to the banquet that I will prepare for them.' A second banquet is invited before Esther makes her real request. <strong>ûmāḥār ʾeʿĕśeh kiddiḇar hammeleḵ</strong> — 'and tomorrow I will do as the king says' — she promises to reveal her petition at the second banquet. The two-banquet strategy builds suspense and ensures Haman's continued presence for the denouement of ch7. It also ensures that the king's curiosity has been fully aroused by two invitations and two deferred revelations.</p>",
    "9": "<p><strong>wayyēṣēʾ Hāmān bayyôm hahûʾ śāmēaḥ wəṭôḇ lēḇ</strong> — 'Haman went out that day joyful and with a glad heart.' <em>Śāmēaḥ wəṭôḇ lēḇ</em> (rejoicing and glad of heart, H8056 + H2896 + H3820) — the idiom for festive contentment. Haman is at the apex of his career: elevated above all officials, invited to two private royal banquets with the queen. <strong>wayyarʾ Hāmān ʾeṯ-Mordoḵay bəšaʿar hammeleḵ wəlōʾ-qām wəlōʾ-zāʿ mimmennû</strong> — 'but when Haman saw Mordecai in the king's gate, and Mordecai neither rose nor trembled before him.' <em>Zāʿ mimmennû</em> (H2111 = to tremble/shake because of him) — not merely failing to bow but showing no physical sign of fear. Mordecai's non-response is total: no rising, no bowing, no trembling — a comprehensive social rebuke.</p>",
    "10": "<p><strong>wayyiṯʾappaq Hāmān wayyāḇôʾ ʾel-bêṯô</strong> — 'Haman restrained himself and went home.' <em>ʾĀpaq</em> (H662, hitpael = to restrain oneself, hold back) — Haman controls his immediate impulse in the public space of the king's gate. But the restraint is temporary: <strong>wayyišlaḥ wayyāḇēʾ ʾeṯ-ʾōhăḇāyw wəʾeṯ-Zereš ʾišṯô</strong> — 'he sent and called for his friends and Zeresh his wife.' The same inner circle that will later pronounce his doom (6:13) is summoned to celebrate his achievements.</p>",
    "11": "<p><strong>wayyəsappēr lāhem Hāmān ʾeṯ-kəḇôḏ ʿōšrô wərōḇ bānāyw</strong> — 'Haman recounted to them the glory of his riches and the multitude of his sons.' <em>Kəḇôḏ ʿōšrô</em> (the glory/weight of his riches, H3519 + H6239) — the same two terms used in 1:4 for the glory of the Persian empire; Haman presents himself as a miniature empire. <strong>wəʾēṯ kol-ʾăšer giḏdelô hammeleḵ</strong> — 'and all that the king had promoted him to' — the king's active role in his elevation. <strong>wəʾēṯ ʾăšer niśśəʾô ʿal-haśśārîm wəʾaḇdê hammeleḵ</strong> — 'and how he had advanced him above the officials and servants of the king.' The recitation is a litany of self-importance: wealth, family, royal favor, governmental supremacy.</p>",
    "12": "<p><strong>wayyōʾmer Hāmān ʾap̄ lōʾ-hēḇîʾāh ʾEsṯēr hammalkāh</strong> — 'Haman also said: Esther the queen brought no one but me with the king to the banquet she had prepared.' The private royal banquet attendance is the pinnacle of his bragging: access to the queen's private table, which no other official has been granted. <strong>wəgam-ləmāḥār ʾănî qārûʾ-lāh ʿim-hammeleḵ</strong> — 'and tomorrow also I am invited by her together with the king.' The second banquet invitation becomes the centerpiece of his self-congratulation — unaware that it is being arranged for his destruction.</p>",
    "13": "<p><strong>wəḵol-zeh ʾênennû šōweh lî</strong> — 'Yet all this is worth nothing to me.' <em>ʾênennû šōweh</em> (it is not worth/comparable, H7737) — the same verb as in 3:8 where the Jews are described as 'not worth' tolerating. Haman's achievement-catalog is all voided by a single sight. <strong>bəḵol-ʿēṯ ʾăšer ʾănî rōʾeh ʾeṯ-Mordoḵay hayyəhûḏî yôšēḇ bəšaʿar hammeleḵ</strong> — 'every time I see Mordecai the Jew sitting at the king's gate.' The title <em>hayyəhûḏî</em> (the Jew) is the specific source of Haman's rage: Mordecai's defiance is inseparable from his Jewish identity, which Haman cannot stand.</p>",
    "14": "<p><strong>watōʾmer lô Zereš ʾišṯô wəḵol-ʾōhăḇāyw</strong> — 'His wife Zeresh and all his friends said to him.' <strong>yaʿăśû-ʿēṣ gāḇōah ḥămiššîm ʾammāh</strong> — 'Let a gallows/stake be made fifty cubits high' — approximately 75 feet (23 meters), tall enough to be visible above the city's rooflines, designed for maximum public display of an execution. <strong>ûḇabboqer ʾĕmōr lammeleḵ wəyitlû ʾeṯ-Mordoḵay ʿālāyw</strong> — 'and in the morning speak to the king, and let Mordecai be hanged on it.' Zeresh and the friends advise Haman to seek royal authorization for Mordecai's immediate execution before the second banquet — clearing the one obstacle to his complete happiness. <strong>ûḇōʾ ʿim-hammeleḵ ʾel-hammišṭeh śāmēaḥ</strong> — 'then go joyfully with the king to the banquet.' The counsel: remove Mordecai, then enjoy the banquet. <strong>wayyîṭaḇ haddāḇār lip̄nê Hāmān wayyaʿaś hāʿēṣ</strong> — 'The plan pleased Haman and he had the gallows made.' <em>Wayyaʿaś hāʿēṣ</em> (and he made the tree/stake) — that same night, Haman had the 50-cubit gallows constructed. The instrument he designed for Mordecai's death will become the instrument of his own.</p>"
  }
}

def main():
    c = load_comm('mkt-original', 'esther')
    before = sum(len(v) for v in c.values())
    merge_comm(c, EST_ORIGINAL_1_5)
    after = sum(len(v) for v in c.values())
    save_comm('mkt-original', 'esther', c)
    added = after - before
    total = sum(len(v) for v in EST_ORIGINAL_1_5.values())
    print(f'esther mkt-original ch 1-5: wrote {total} verses ({added} new)')
    # Verify
    import json as _j
    il = _j.loads((ROOT / 'data/interlinear/esther.json').read_text())
    out = _j.loads((ROOT / 'data/commentary/mkt-original/esther.json').read_text())
    all_ok = True
    for ch in range(1, 6):
        il_vs = set(il[str(ch)].keys())
        out_vs = set(out.get(str(ch), {}).keys())
        missing = il_vs - out_vs
        if missing:
            print(f'  ch{ch}: MISSING {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'  ch{ch}: complete ({len(out_vs)} verses)')
    if all_ok:
        print('All verses present ✓')

if __name__ == '__main__':
    main()
